const highlights = [
  {
    title: "Hizli Baslangic",
    text: "Fikirden urune giden sureci sade bir yapi ile hizlandir."
  },
  {
    title: "Net Takip",
    text: "Planlarini, gorevlerini ve teslimlerini tek bir akis uzerinden yonet."
  },
  {
    title: "Olceklenebilir Mimari",
    text: "Kucuk bir MVP ile basla, buyudukce ayni temel uzerinde devam et."
  }
];

export default function Home() {
  return (
    <main className="min-h-screen px-6 py-10 sm:px-10 md:px-16">
      <div className="mx-auto flex w-full max-w-6xl flex-col gap-16">
        <header className="flex items-center justify-between rounded-2xl border border-slate-200/70 bg-white/70 px-5 py-4 backdrop-blur">
          <div className="text-lg font-semibold tracking-tight text-slate-900">Ozmoz</div>
          <button className="rounded-xl bg-slate-900 px-4 py-2 text-sm font-medium text-white transition hover:bg-slate-700">
            Erken Erişim
          </button>
        </header>

        <section className="grid gap-8 md:grid-cols-2 md:items-center">
          <div className="space-y-6">
            <span className="inline-flex rounded-full border border-blue-100 bg-blue-50 px-3 py-1 text-xs font-medium text-blue-600">
              Modern ve sade deneyim
            </span>
            <h1 className="text-4xl font-bold leading-tight text-slate-900 sm:text-5xl">
              Ozmoz ile urun fikrini hizla gercege donustur.
            </h1>
            <p className="max-w-xl text-base leading-relaxed text-slate-600 sm:text-lg">
              Cekirdek ihtiyaclara odaklanan, temiz bir arayuz ve net bir ilerleme akisi ile
              gelistirme surecini daha odulebilir hale getir.
            </p>
            <div className="flex flex-wrap gap-3">
              <button className="rounded-xl bg-blue-600 px-5 py-3 text-sm font-semibold text-white transition hover:bg-blue-500">
                Hemen Basla
              </button>
              <button className="rounded-xl border border-slate-300 bg-white px-5 py-3 text-sm font-semibold text-slate-700 transition hover:bg-slate-50">
                Dokumani Incele
              </button>
            </div>
          </div>

          <div className="rounded-3xl border border-slate-200/80 bg-white/80 p-6 shadow-sm backdrop-blur">
            <div className="space-y-4">
              <h2 className="text-lg font-semibold text-slate-900">Neden Ozmoz?</h2>
              <p className="text-sm leading-relaxed text-slate-600">
                Gereksiz karmasadan uzak, odakli bir urun gelistirme deneyimi. Planla, takip et,
                yayina hazirla.
              </p>
              <div className="grid gap-3">
                {highlights.map((item) => (
                  <article
                    key={item.title}
                    className="rounded-xl border border-slate-200 bg-slate-50/80 p-4"
                  >
                    <h3 className="text-sm font-semibold text-slate-900">{item.title}</h3>
                    <p className="mt-1 text-sm text-slate-600">{item.text}</p>
                  </article>
                ))}
              </div>
            </div>
          </div>
        </section>
      </div>
    </main>
  );
}
